import{_ as t,c as p,b as o,a as s,d as a,e as c,r as l,o as i}from"./app-CvT2DUHU.js";const d={},r={href:"https://github.com/coolclaws/deerflow-book",target:"_blank",rel:"noopener noreferrer"};function u(k,n){const e=l("ExternalLinkIcon");return i(),p("div",null,[n[2]||(n[2]=o(`<h1 id="第-4-章-langgraph-引擎-图驱动的-agent-编排" tabindex="-1"><a class="header-anchor" href="#第-4-章-langgraph-引擎-图驱动的-agent-编排"><span>第 4 章　LangGraph 引擎：图驱动的 Agent 编排</span></a></h1><p>DeerFlow 的 Agent 系统并非手写的 while 循环，而是构建在 LangGraph 之上。LangGraph 将 Agent 的推理-行动循环抽象为一张有向图，每个节点是一个计算单元，边定义了控制流。本章解析 DeerFlow 如何利用 LangGraph 的图抽象、状态管理和持久化机制来驱动整个 Agent 系统。</p><h2 id="_4-1-langgraph-是什么" tabindex="-1"><a class="header-anchor" href="#_4-1-langgraph-是什么"><span>4.1 LangGraph 是什么</span></a></h2><p>LangGraph 是 LangChain 团队推出的图驱动 Agent 编排框架。它的核心抽象是 <strong>StateGraph</strong>——一种以状态为中心的有向图：</p><ul><li><strong>节点（Node）</strong>：图中的计算单元，每个节点接收当前状态、执行操作、返回状态更新。</li><li><strong>边（Edge）</strong>：节点之间的连接，定义执行顺序。</li><li><strong>条件边（Conditional Edge）</strong>：根据当前状态动态决定下一个节点，实现分支逻辑。</li><li><strong>状态（State）</strong>：一个 TypedDict，在整个图的执行过程中被传递和更新。</li></ul><p>与传统的 DAG 工作流引擎不同，LangGraph 原生支持<strong>循环</strong>——这正是 Agent 推理所需要的。LLM 调用工具后需要再次思考，再次调用工具……这个循环在 LangGraph 中通过条件边自然表达，无需任何特殊处理。</p><p>为什么不用简单的 while 循环来实现 Agent？因为图抽象带来了三个关键能力：第一，每个节点执行后可以自动保存状态快照，实现断点恢复；第二，图的拓扑结构可以在运行时被检查和可视化，便于调试和监控；第三，条件边的路由逻辑与节点的业务逻辑解耦，修改控制流不需要改动节点代码。这些能力对于生产级 Agent 系统至关重要。</p><h2 id="_4-2-deerflow-如何使用-langgraph" tabindex="-1"><a class="header-anchor" href="#_4-2-deerflow-如何使用-langgraph"><span>4.2 DeerFlow 如何使用 LangGraph</span></a></h2><p>DeerFlow 没有直接操作 <code>StateGraph</code> API 来手动添加节点和边，而是使用了 LangChain 提供的 <code>create_react_agent()</code> 工厂函数。这个函数内部自动构建了一个标准的 ReAct 图。DeerFlow 通过 <code>create_agent()</code> 对其进行了一层封装：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token comment"># 简化后的调用链</span></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">make_lead_agent</span><span class="token punctuation">(</span>config<span class="token punctuation">:</span> RunnableConfig<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">return</span> create_agent<span class="token punctuation">(</span></span>
<span class="line">        model<span class="token operator">=</span>create_chat_model<span class="token punctuation">(</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        tools<span class="token operator">=</span>get_available_tools<span class="token punctuation">(</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        middleware<span class="token operator">=</span>_build_middlewares<span class="token punctuation">(</span>config<span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        system_prompt<span class="token operator">=</span>apply_prompt_template<span class="token punctuation">(</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        state_schema<span class="token operator">=</span>ThreadState<span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>create_agent()</code> 最终调用 <code>create_react_agent()</code>，将 DeerFlow 的模型、工具、中间件和状态模式传入。返回的是一个编译好的 LangGraph <code>CompiledGraph</code> 对象，可以直接 <code>invoke()</code> 或 <code>stream()</code> 执行。</p><p>这种设计的好处是：DeerFlow 不需要关心 ReAct 循环的具体实现细节（节点怎么连、条件怎么判断），只需要专注于<strong>提供什么模型、什么工具、什么中间件、什么状态</strong>。图的结构由 LangGraph 框架保证正确性。</p><p>这里有一个重要的分层：<code>make_lead_agent()</code> 是 DeerFlow 特有的工厂函数，负责从运行时配置中提取模型名称、工具组、中间件链等参数；<code>create_agent()</code> 是通用的 Agent 创建函数，负责将这些参数适配到 LangGraph 的 <code>create_react_agent()</code> 接口上。这种两层工厂的设计让 Sub-agent 也能复用 <code>create_agent()</code>，只是传入不同的参数组合。换言之，Lead Agent 和 Sub-agent 的底层图结构完全相同，区别仅在于挂载的工具和中间件不同。</p><h2 id="_4-3-agentstate-→-threadstate" tabindex="-1"><a class="header-anchor" href="#_4-3-agentstate-→-threadstate"><span>4.3 AgentState → ThreadState</span></a></h2><p>LangGraph 的 <code>create_react_agent()</code> 默认使用 <code>AgentState</code> 作为状态模式，它只包含一个 <code>messages</code> 字段用于存储对话消息。但 DeerFlow 的 Agent 需要管理远比消息更多的运行时数据。因此，<code>ThreadState</code> 继承了 <code>AgentState</code> 并扩展了 7 个自定义字段：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">ThreadState</span><span class="token punctuation">(</span>AgentState<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    sandbox<span class="token punctuation">:</span> NotRequired<span class="token punctuation">[</span>SandboxState <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">]</span></span>
<span class="line">    thread_data<span class="token punctuation">:</span> NotRequired<span class="token punctuation">[</span>ThreadDataState <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">]</span></span>
<span class="line">    title<span class="token punctuation">:</span> NotRequired<span class="token punctuation">[</span><span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">]</span></span>
<span class="line">    artifacts<span class="token punctuation">:</span> Annotated<span class="token punctuation">[</span><span class="token builtin">list</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">]</span><span class="token punctuation">,</span> merge_artifacts<span class="token punctuation">]</span></span>
<span class="line">    todos<span class="token punctuation">:</span> NotRequired<span class="token punctuation">[</span><span class="token builtin">list</span> <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">]</span></span>
<span class="line">    uploaded_files<span class="token punctuation">:</span> NotRequired<span class="token punctuation">[</span><span class="token builtin">list</span><span class="token punctuation">[</span><span class="token builtin">dict</span><span class="token punctuation">]</span> <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">]</span></span>
<span class="line">    viewed_images<span class="token punctuation">:</span> Annotated<span class="token punctuation">[</span><span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> ViewedImageData<span class="token punctuation">]</span><span class="token punctuation">,</span> merge_viewed_images<span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>各字段的职责如下：</p><table><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>sandbox</code></td><td><code>SandboxState</code></td><td>沙箱环境状态，包含 <code>sandbox_id</code>，由 <code>SandboxMiddleware</code> 管理生命周期</td></tr><tr><td><code>thread_data</code></td><td><code>ThreadDataState</code></td><td>线程工作目录，包含 <code>workspace_path</code>、<code>uploads_path</code>、<code>outputs_path</code> 三个路径</td></tr><tr><td><code>title</code></td><td><code>str</code></td><td>对话标题，由 <code>TitleMiddleware</code> 在首轮交互后自动生成</td></tr><tr><td><code>artifacts</code></td><td><code>list[str]</code></td><td>产出物路径列表（如生成的报告文件），使用 reducer 去重合并</td></tr><tr><td><code>todos</code></td><td><code>list</code></td><td>Plan Mode 下的任务清单，由 <code>TodoMiddleware</code> 维护</td></tr><tr><td><code>uploaded_files</code></td><td><code>list[dict]</code></td><td>用户上传文件的元数据，由 <code>UploadsMiddleware</code> 注入上下文</td></tr><tr><td><code>viewed_images</code></td><td><code>dict</code></td><td>已查看图片的缓存数据（含 base64），由 <code>ViewImageMiddleware</code> 使用</td></tr></tbody></table><p>其中 <code>SandboxState</code> 和 <code>ThreadDataState</code> 是两个子状态类型：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">SandboxState</span><span class="token punctuation">(</span>TypedDict<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    sandbox_id<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">ThreadDataState</span><span class="token punctuation">(</span>TypedDict<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    workspace_path<span class="token punctuation">:</span> <span class="token builtin">str</span></span>
<span class="line">    uploads_path<span class="token punctuation">:</span> <span class="token builtin">str</span></span>
<span class="line">    outputs_path<span class="token punctuation">:</span> <span class="token builtin">str</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>ThreadState</code> 通过 <code>state_schema=ThreadState</code> 参数传给 <code>create_agent()</code>，LangGraph 会在图执行过程中自动管理这个状态的传递和更新。</p><h2 id="_4-4-自定义-reducer-函数" tabindex="-1"><a class="header-anchor" href="#_4-4-自定义-reducer-函数"><span>4.4 自定义 Reducer 函数</span></a></h2><p>在 LangGraph 中，当多个节点（或中间件）对同一个状态字段进行更新时，需要一个<strong>合并策略</strong>来决定如何处理新旧值。这就是 Reducer 的作用。<code>ThreadState</code> 中有两个字段使用了自定义 Reducer。</p><p><strong><code>merge_artifacts</code>：去重保序合并</strong></p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">merge_artifacts</span><span class="token punctuation">(</span>existing<span class="token punctuation">:</span> <span class="token builtin">list</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">]</span> <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">,</span> new<span class="token punctuation">:</span> <span class="token builtin">list</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">]</span> <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">list</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">]</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">if</span> existing <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> new <span class="token keyword">or</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line">    <span class="token keyword">if</span> new <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> existing</span>
<span class="line">    <span class="token keyword">return</span> <span class="token builtin">list</span><span class="token punctuation">(</span><span class="token builtin">dict</span><span class="token punctuation">.</span>fromkeys<span class="token punctuation">(</span>existing <span class="token operator">+</span> new<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这个 Reducer 用 <code>dict.fromkeys()</code> 实现去重——利用字典键的唯一性，同时保留插入顺序（Python 3.7+ 的 dict 保证有序）。这意味着当多个工具调用各自生成了 artifact 文件路径时，最终列表既不会有重复项，也不会丢失任何一个。</p><p><strong><code>merge_viewed_images</code>：带清空语义的字典合并</strong></p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">merge_viewed_images</span><span class="token punctuation">(</span></span>
<span class="line">    existing<span class="token punctuation">:</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> ViewedImageData<span class="token punctuation">]</span> <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">,</span></span>
<span class="line">    new<span class="token punctuation">:</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> ViewedImageData<span class="token punctuation">]</span> <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> ViewedImageData<span class="token punctuation">]</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">if</span> existing <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> new <span class="token keyword">or</span> <span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">if</span> new <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> existing</span>
<span class="line">    <span class="token keyword">if</span> <span class="token keyword">not</span> new<span class="token punctuation">:</span>  <span class="token comment"># new == {}，空字典表示&quot;清空所有&quot;</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token punctuation">{</span><span class="token operator">**</span>existing<span class="token punctuation">,</span> <span class="token operator">**</span>new<span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这个 Reducer 有一个特殊约定：当 <code>new</code> 为空字典 <code>{}</code> 时，不是&quot;没有更新&quot;，而是&quot;清空所有已查看的图片&quot;。这是一种中间件清理模式——<code>ViewImageMiddleware</code> 在处理完图片并将 base64 数据注入到消息上下文后，会发送一个空字典来重置状态，避免大量图片数据在后续轮次中持续占用内存。</p><p>为什么 Reducer 如此重要？因为 LangGraph 的状态更新不是简单的覆盖。在一个包含多层中间件的系统中，如果中间件 A 写入了 <code>artifacts = [&quot;a.md&quot;]</code>，中间件 B 又写入了 <code>artifacts = [&quot;b.md&quot;]</code>，没有 Reducer 的情况下后者会覆盖前者。有了 <code>merge_artifacts</code>，两个值会被合并为 <code>[&quot;a.md&quot;, &quot;b.md&quot;]</code>。</p><h2 id="_4-5-checkpointer-对话状态持久化" tabindex="-1"><a class="header-anchor" href="#_4-5-checkpointer-对话状态持久化"><span>4.5 Checkpointer：对话状态持久化</span></a></h2><p>LangGraph 的 Checkpointer 机制负责在每个图节点执行后保存一份状态快照。这使得对话可以跨请求恢复——用户关闭浏览器后回来，Agent 仍然记得之前的对话上下文、沙箱状态和产出物列表。</p><p>DeerFlow 提供了两种 Checkpointer Provider，适用于不同的运行场景。</p><p><strong>异步 Provider（用于 FastAPI 服务端）：</strong></p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token comment"># backend/src/agents/checkpointer/async_provider.py</span></span>
<span class="line"></span>
<span class="line"><span class="token decorator annotation punctuation">@asynccontextmanager</span></span>
<span class="line"><span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">make_checkpointer</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    checkpointer_type <span class="token operator">=</span> get_env<span class="token punctuation">(</span><span class="token string">&quot;CHECKPOINTER&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;memory&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> checkpointer_type <span class="token operator">==</span> <span class="token string">&quot;postgres&quot;</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">async</span> <span class="token keyword">with</span> AsyncPostgresSaver<span class="token punctuation">.</span>from_conn_string<span class="token punctuation">(</span>conn_string<span class="token punctuation">)</span> <span class="token keyword">as</span> saver<span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">await</span> saver<span class="token punctuation">.</span>setup<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">            <span class="token keyword">yield</span> saver</span>
<span class="line">    <span class="token keyword">elif</span> checkpointer_type <span class="token operator">==</span> <span class="token string">&quot;sqlite&quot;</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">async</span> <span class="token keyword">with</span> AsyncSqliteSaver<span class="token punctuation">.</span>from_conn_string<span class="token punctuation">(</span>db_path<span class="token punctuation">)</span> <span class="token keyword">as</span> saver<span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">await</span> saver<span class="token punctuation">.</span>setup<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">            <span class="token keyword">yield</span> saver</span>
<span class="line">    <span class="token keyword">else</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">yield</span> MemorySaver<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用 <code>async with</code> 上下文管理器，确保数据库连接在服务生命周期结束时被正确关闭。这与 FastAPI 的 <code>lifespan</code> 事件天然匹配——在服务启动时 <code>yield</code> 之前完成初始化，在服务关闭时 <code>yield</code> 之后自动释放资源。对于 Postgres 和 SQLite 后端，<code>setup()</code> 方法会自动创建所需的数据库表结构，首次运行无需手动建表。</p><p><strong>同步 Provider（用于 CLI 和嵌入式客户端）：</strong></p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token comment"># backend/src/agents/checkpointer/provider.py</span></span>
<span class="line"></span>
<span class="line">_checkpointer <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">get_checkpointer</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">global</span> _checkpointer</span>
<span class="line">    <span class="token keyword">if</span> _checkpointer <span class="token keyword">is</span> <span class="token keyword">not</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> _checkpointer</span>
<span class="line"></span>
<span class="line">    checkpointer_type <span class="token operator">=</span> get_env<span class="token punctuation">(</span><span class="token string">&quot;CHECKPOINTER&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;memory&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> checkpointer_type <span class="token operator">==</span> <span class="token string">&quot;postgres&quot;</span><span class="token punctuation">:</span></span>
<span class="line">        _checkpointer <span class="token operator">=</span> PostgresSaver<span class="token punctuation">(</span>conn_string<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">elif</span> checkpointer_type <span class="token operator">==</span> <span class="token string">&quot;sqlite&quot;</span><span class="token punctuation">:</span></span>
<span class="line">        _checkpointer <span class="token operator">=</span> SqliteSaver<span class="token punctuation">(</span>db_path<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">else</span><span class="token punctuation">:</span></span>
<span class="line">        _checkpointer <span class="token operator">=</span> MemorySaver<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> _checkpointer</span>
<span class="line"></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">reset_checkpointer</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">global</span> _checkpointer</span>
<span class="line">    _checkpointer <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>同步 Provider 采用单例模式：全局变量 <code>_checkpointer</code> 缓存实例，避免每次调用都创建新连接。<code>reset_checkpointer()</code> 提供清理接口，主要用于测试场景中重置全局状态。为什么需要两套 Provider？因为 FastAPI 的异步运行时要求所有 I/O 操作都是非阻塞的，使用同步的数据库驱动会阻塞事件循环；而 CLI 和嵌入式客户端运行在同步上下文中，使用异步 Provider 反而增加不必要的复杂度。两套 Provider 共享相同的后端选择逻辑，只是底层驱动不同。</p><p>三种后端的适用场景：</p><table><thead><tr><th>后端</th><th>适用场景</th><th>持久性</th></tr></thead><tbody><tr><td><code>memory</code></td><td>开发调试、单次运行</td><td>进程退出即丢失</td></tr><tr><td><code>sqlite</code></td><td>单机部署、嵌入式客户端</td><td>持久化到本地文件</td></tr><tr><td><code>postgres</code></td><td>生产环境、多实例部署</td><td>持久化到数据库，支持多节点共享</td></tr></tbody></table><h2 id="_4-6-react-循环在-langgraph-中的实现" tabindex="-1"><a class="header-anchor" href="#_4-6-react-循环在-langgraph-中的实现"><span>4.6 ReAct 循环在 LangGraph 中的实现</span></a></h2><p><code>create_react_agent()</code> 内部构建的图结构可以简化为三个核心组件：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text" data-title="text"><pre><code><span class="line">┌─────────────┐</span>
<span class="line">│  Agent Node  │ ← LLM 调用，生成回复或 tool_calls</span>
<span class="line">└──────┬──────┘</span>
<span class="line">       │</span>
<span class="line">   ┌───▼────┐</span>
<span class="line">   │ 条件边  │ ← 检查：response 中有 tool_calls 吗？</span>
<span class="line">   └───┬────┘</span>
<span class="line">      ╱ ╲</span>
<span class="line">    有     无</span>
<span class="line">    ↓      ↓</span>
<span class="line">┌──────┐  ┌─────┐</span>
<span class="line">│ Tool │  │ END │</span>
<span class="line">│ Node │  └─────┘</span>
<span class="line">└──┬───┘</span>
<span class="line">   │</span>
<span class="line">   └──→ 回到 Agent Node（循环）</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol><li><strong>Agent Node</strong>：将当前消息列表发送给 LLM，获取响应。如果模型决定需要调用工具，响应中会包含 <code>tool_calls</code> 字段。</li><li><strong>条件边</strong>：检查 LLM 响应中是否存在 <code>tool_calls</code>。如果有，路由到 Tool Node；如果没有，路由到 END，结束本轮执行。</li><li><strong>Tool Node</strong>：执行 LLM 请求的工具调用，将结果作为 <code>ToolMessage</code> 追加到消息列表，然后<strong>回到 Agent Node</strong>。</li></ol><p>这就是经典的 ReAct（Reasoning + Acting）循环：思考 → 行动 → 观察 → 再思考。但与手写 while 循环不同，LangGraph 的图实现带来了额外的好处：每个节点执行后都会触发 Checkpointer 保存快照，这意味着即使在工具执行过程中服务崩溃，重启后也可以从上一个快照恢复。</p><p>需要特别说明的是，DeerFlow 的中间件管道并不是图中的独立节点，而是挂载在 Agent Node 上的拦截器。中间件在 Agent Node 执行前后运行，可以修改输入的消息列表（前置处理）或修改输出的状态更新（后置处理）。从 LangGraph 的视角看，整个中间件链和 LLM 调用是一个原子操作，共享同一个 Agent Node。这种设计避免了将中间件逻辑散落在多个图节点中，保持了图拓扑的简洁性。</p><h2 id="_4-7-从多节点图到单一-lead-agent" tabindex="-1"><a class="header-anchor" href="#_4-7-从多节点图到单一-lead-agent"><span>4.7 从多节点图到单一 Lead Agent</span></a></h2><p>DeerFlow 1.0（当时名为 DeerFlow）采用的是一个包含 5 个节点的复杂 StateGraph：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text" data-title="text"><pre><code><span class="line">Coordinator → Planner → [Researcher, Coder] → Reporter</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>每个节点是一个专门化的 Agent，有自己独立的 system prompt 和工具集。Coordinator 负责任务分派，Planner 负责制定计划，Researcher 和 Coder 并行执行，Reporter 汇总输出。节点之间通过条件边连接，形成一个固定的多步流水线。</p><p>DeerFlow 2.0 做了一次大胆的架构简化：<strong>将 5 个节点压缩为 1 个 Lead Agent</strong>。原本由图结构承载的编排逻辑，被迁移到了工具集和中间件管道中：</p><ul><li>Coordinator 的任务分派能力 → 成为 Lead Agent 的 system prompt 中的编排指令</li><li>Planner 的规划能力 → 成为 <code>TodoMiddleware</code> + Plan Mode</li><li>Researcher / Coder 的专门能力 → 成为可通过 <code>task</code> 工具动态启动的 Sub-agent</li><li>Reporter 的汇总能力 → 成为 <code>present_file</code> 内置工具</li></ul><p>这次重构的设计哲学可以总结为一句话：<strong>能力从图结构迁移到工具集和中间件</strong>。图变简单了，但 Agent 的能力并没有减少——它只是从&quot;硬编码在图拓扑中&quot;变成了&quot;由 LLM 在运行时动态选择&quot;。</p><p>值得注意的是，Sub-agent 本身仍然是 LangGraph Agent。它们同样通过 <code>create_agent()</code> 创建，拥有自己的 ReAct 循环，只不过中间件链更短——只有 2 个中间件（相比 Lead Agent 的最多 11 个）。Sub-agent 不需要标题生成、对话摘要、上传文件注入等功能，因此只保留了最基本的中间件。</p><p>这种架构演进反映了 AI Agent 领域的一个重要趋势：随着大语言模型能力的增强，越来越多的编排逻辑可以交给模型自身来决策，而不是硬编码在代码中。固定的多节点流水线虽然可预测，但缺乏灵活性——模型无法跳过不必要的步骤，也无法根据任务复杂度动态调整执行路径。单一 Lead Agent 配合丰富的工具集，让模型拥有了更大的决策空间，也让系统更容易扩展新能力——只需添加新工具或新中间件，无需修改图的拓扑结构。</p><h2 id="小结" tabindex="-1"><a class="header-anchor" href="#小结"><span>小结</span></a></h2><ul><li><strong>LangGraph 的核心价值</strong>在于将 Agent 的 ReAct 循环表达为图结构，原生支持循环、条件路由和状态持久化，避免了手写 while 循环的脆弱性。</li><li><strong>ThreadState</strong> 在 AgentState 基础上扩展了 7 个业务字段，通过 <code>Annotated</code> + Reducer 模式实现安全的状态合并，<code>merge_artifacts</code> 去重保序，<code>merge_viewed_images</code> 支持清空语义。</li><li><strong>Checkpointer</strong> 提供异步和同步两种 Provider，支持 memory/sqlite/postgres 三种后端，覆盖从开发到生产的全部场景。</li><li><strong>从 5 节点图到单一 Lead Agent</strong> 的架构演进，体现了 DeerFlow 2.0 的核心设计哲学：能力从图结构迁移到工具集和中间件，让图保持简单，让 LLM 在运行时决定如何编排。</li></ul><hr>`,59)),s("p",null,[n[1]||(n[1]=a("来源: ",-1)),s("a",r,[n[0]||(n[0]=a("DeerFlow Book",-1)),c(e)])])])}const v=t(d,[["render",u]]),h=JSON.parse('{"path":"/docs/Agent/DeerFlow/04-langgraph-engine.html","title":"第 4 章　LangGraph 引擎：图驱动的 Agent 编排","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"4.1 LangGraph 是什么","slug":"_4-1-langgraph-是什么","link":"#_4-1-langgraph-是什么","children":[]},{"level":2,"title":"4.2 DeerFlow 如何使用 LangGraph","slug":"_4-2-deerflow-如何使用-langgraph","link":"#_4-2-deerflow-如何使用-langgraph","children":[]},{"level":2,"title":"4.3 AgentState → ThreadState","slug":"_4-3-agentstate-→-threadstate","link":"#_4-3-agentstate-→-threadstate","children":[]},{"level":2,"title":"4.4 自定义 Reducer 函数","slug":"_4-4-自定义-reducer-函数","link":"#_4-4-自定义-reducer-函数","children":[]},{"level":2,"title":"4.5 Checkpointer：对话状态持久化","slug":"_4-5-checkpointer-对话状态持久化","link":"#_4-5-checkpointer-对话状态持久化","children":[]},{"level":2,"title":"4.6 ReAct 循环在 LangGraph 中的实现","slug":"_4-6-react-循环在-langgraph-中的实现","link":"#_4-6-react-循环在-langgraph-中的实现","children":[]},{"level":2,"title":"4.7 从多节点图到单一 Lead Agent","slug":"_4-7-从多节点图到单一-lead-agent","link":"#_4-7-从多节点图到单一-lead-agent","children":[]},{"level":2,"title":"小结","slug":"小结","link":"#小结","children":[]}],"git":{},"filePathRelative":"docs/Agent/DeerFlow/04-langgraph-engine.md"}');export{v as comp,h as data};
